"use client";

import { useState } from "react";
import Link from "next/link";
import { Eye, EyeOff, Lock, Mail, ArrowRight } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";

export default function LoginPage() {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [showPassword, setShowPassword] = useState(false);
    const [rememberMe, setRememberMe] = useState(false);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        // Mock login ΓÇö redirect to dashboard
        window.location.href = "/";
    };

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Logo & Welcome */}
            <div className="text-center space-y-2">
                <div className="inline-flex h-16 w-16 items-center justify-center rounded-2xl bg-primary text-3xl shadow-lg shadow-primary/30 mb-2">
                    ≡ƒÉ╖
                </div>
                <h1 className="text-2xl font-bold text-foreground tracking-tight">
                    Keuanganku
                </h1>
                <p className="text-sm text-muted-foreground">
                    Masuk untuk kelola keuanganmu Γ£¿
                </p>
            </div>

            {/* Card */}
            <div className="rounded-3xl border border-primary/15 bg-white/80 backdrop-blur-sm p-7 shadow-xl shadow-primary/5">
                <form onSubmit={handleSubmit} className="space-y-5">
                    {/* Email */}
                    <div className="space-y-1.5">
                        <Label className="text-xs font-medium text-foreground">Email</Label>
                        <div className="relative">
                            <Mail className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                            <Input
                                type="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                placeholder="nama@email.com"
                                className="h-11 pl-9 rounded-xl border-primary/15 focus-visible:ring-primary/30 bg-white"
                                required
                            />
                        </div>
                    </div>

                    {/* Password */}
                    <div className="space-y-1.5">
                        <Label className="text-xs font-medium text-foreground">Kata Sandi</Label>
                        <div className="relative">
                            <Lock className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                            <Input
                                type={showPassword ? "text" : "password"}
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                                className="h-11 pl-9 pr-10 rounded-xl border-primary/15 focus-visible:ring-primary/30 bg-white"
                                required
                            />
                            <button
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                            >
                                {showPassword ? (
                                    <EyeOff className="h-4 w-4" />
                                ) : (
                                    <Eye className="h-4 w-4" />
                                )}
                            </button>
                        </div>
                    </div>

                    {/* Remember & Forgot */}
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-2">
                            <Switch
                                id="remember"
                                checked={rememberMe}
                                onCheckedChange={setRememberMe}
                                className="scale-80"
                            />
                            <Label htmlFor="remember" className="text-xs text-muted-foreground cursor-pointer">
                                Ingat saya
                            </Label>
                        </div>
                        <button type="button" className="text-xs text-primary hover:underline font-medium">
                            Lupa kata sandi?
                        </button>
                    </div>

                    {/* Submit */}
                    <Button
                        type="submit"
                        className="w-full h-11 rounded-xl bg-primary hover:bg-primary/90 font-semibold text-sm group shadow-lg shadow-primary/25 transition-all"
                        disabled={!email || !password}
                    >
                        Masuk
                        <ArrowRight className="h-4 w-4 ml-1.5 group-hover:translate-x-0.5 transition-transform" />
                    </Button>
                </form>

                {/* Divider */}
                <div className="relative my-5">
                    <div className="absolute inset-0 flex items-center">
                        <div className="w-full border-t border-primary/10" />
                    </div>
                    <div className="relative flex justify-center">
                        <span className="bg-white/80 px-3 text-[11px] text-muted-foreground">atau</span>
                    </div>
                </div>

                {/* Social */}
                <Button
                    type="button"
                    variant="outline"
                    className="w-full h-11 rounded-xl border-primary/15 text-sm font-medium hover:bg-primary/5 transition-all"
                >
                    <svg className="h-4 w-4 mr-2" viewBox="0 0 24 24">
                        <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 0 1-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z" fill="#4285F4" />
                        <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                        <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                        <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
                    </svg>
                    Masuk dengan Google
                </Button>
            </div>

            {/* Footer */}
            <p className="text-center text-xs text-muted-foreground">
                Belum punya akun?{" "}
                <button className="text-primary hover:underline font-medium">
                    Daftar sekarang
                </button>
            </p>
        </div>
    );
}

"use client";

import { useMemo } from "react";
import {
    ResponsiveContainer,
    BarChart,
    Bar,
    LineChart,
    Line,
    PieChart,
    Pie,
    Cell,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
} from "recharts";
import { Loader2 } from "lucide-react";
import { formatCurrency } from "@/lib/utils";
import { MONTH_NAMES } from "@/lib/constants";
import { useUIStore } from "@/stores/ui-store";
import { useMonthlyTrend, useBudgetStatus, useCategories, useTransactions } from "@/hooks/use-queries";

function ChartTooltip({ active, payload, label }: { active?: boolean; payload?: Array<{ value: number; color: string; name: string }>; label?: string }) {
    if (!active || !payload) return null;
    return (
        <div className="rounded-xl border border-primary/15 bg-white/95 backdrop-blur-sm p-3 shadow-xl shadow-primary/5">
            <p className="text-xs font-semibold text-foreground mb-1.5">{label}</p>
            {payload.map((e) => (
                <div key={e.name} className="flex items-center gap-2">
                    <div className="h-2 w-2 rounded-full" style={{ backgroundColor: e.color }} />
                    <span className="text-[11px] text-muted-foreground">{e.name}</span>
                    <span className="text-[11px] font-currency font-semibold text-foreground ml-auto">
                        {e.name === "% Rasio" ? `${e.value}%` : formatCurrency(e.value)}
                    </span>
                </div>
            ))}
        </div>
    );
}

const COLORS = ["#a855f7", "#d946ef", "#3b82f6"];

export default function ReportsPage() {
    const { currentMonth, currentYear } = useUIStore();

    const { data: trendData = [], isLoading: loadingTrend } = useMonthlyTrend(currentMonth, currentYear);
    const { data: budgetStatus = [], isLoading: loadingBudget } = useBudgetStatus(currentMonth, currentYear);
    const { data: categories = [], isLoading: loadingCats } = useCategories();
    const { data: transactions = [], isLoading: loadingTxns } = useTransactions(currentMonth, currentYear);

    // --- Data prep ---
    const barData = useMemo(() => {
        return trendData.map((d) => ({
            name: MONTH_NAMES[d.month - 1]?.substring(0, 3) ?? `${d.month}`,
            Pemasukan: d.income,
            Pengeluaran: d.expenses,
        }));
    }, [trendData]);

    const savingsLineData = useMemo(() => {
        return trendData.map((d) => ({
            name: MONTH_NAMES[d.month - 1]?.substring(0, 3) ?? `${d.month}`,
            Tabungan: d.savings,
            "% Rasio": d.income > 0 ? Math.round((d.savings / d.income) * 100) : 0,
        }));
    }, [trendData]);

    const pieData = useMemo(() => {
        return budgetStatus.map((s, i) => ({
            name: s.category,
            value: s.spent,
            fill: COLORS[i % COLORS.length],
        })).filter(s => s.value > 0);
    }, [budgetStatus]);

    const categorySpending = useMemo(() => {
        return categories
            .filter((c) => c.mainCategory !== "Savings")
            .map((cat) => {
                const spent = transactions
                    .filter((t) => t.categoryId === cat.id && t.amount < 0)
                    .reduce((sum, t) => sum + Math.abs(t.amount), 0);
                return { name: cat.name, Pengeluaran: spent };
            })
            .filter((c) => c.Pengeluaran > 0)
            .sort((a, b) => b.Pengeluaran - a.Pengeluaran);
    }, [categories, transactions]);

    const isLoading = loadingTrend || loadingBudget || loadingCats || loadingTxns;

    if (isLoading) {
        return (
            <div className="space-y-6 flex flex-col items-center justify-center h-64">
                <Loader2 className="h-8 w-8 text-primary animate-spin" />
                <p className="text-sm text-muted-foreground">Menyiapkan laporan...</p>
            </div>
        );
    }

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            {/* Header */}
            <div>
                <h2 className="text-xl font-bold text-foreground">
                    Laporan Keuangan ≡ƒôè
                </h2>
                <p className="text-sm text-muted-foreground mt-1">
                    Analisis dan visualisasi keuanganmu
                </p>
            </div>

            {/* Chart Grid */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                {/* 1. Income vs Expenses Bar Chart */}
                <div className="rounded-2xl border border-primary/10 bg-white p-5">
                    <div className="flex items-center justify-between mb-4">
                        <div>
                            <h3 className="text-sm font-semibold text-foreground">Pemasukan vs Pengeluaran</h3>
                            <p className="text-xs text-muted-foreground mt-0.5">6 bulan terakhir</p>
                        </div>
                        <span className="text-sm">≡ƒôè</span>
                    </div>
                    <div className="h-[250px]">
                        {barData.length > 0 ? (
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart data={barData} margin={{ top: 5, right: 5, left: -15, bottom: 5 }}>
                                    <CartesianGrid strokeDasharray="3 3" stroke="#f3e8ff" vertical={false} />
                                    <XAxis dataKey="name" tick={{ fontSize: 11, fill: "#9ca3af" }} axisLine={{ stroke: "#f3e8ff" }} tickLine={false} />
                                    <YAxis tick={{ fontSize: 10, fill: "#9ca3af" }} axisLine={false} tickLine={false} tickFormatter={(v: number) => v >= 1_000_000 ? `${(v / 1_000_000).toFixed(0)}jt` : `${v / 1000}k`} />
                                    <Tooltip content={<ChartTooltip />} />
                                    <Legend iconType="circle" iconSize={8} wrapperStyle={{ fontSize: "11px", paddingTop: "8px" }} />
                                    <Bar dataKey="Pemasukan" fill="#22c55e" radius={[6, 6, 0, 0]} barSize={20} />
                                    <Bar dataKey="Pengeluaran" fill="#a855f7" radius={[6, 6, 0, 0]} barSize={20} />
                                </BarChart>
                            </ResponsiveContainer>
                        ) : (
                            <div className="h-full flex items-center justify-center text-xs text-muted-foreground border border-dashed border-primary/10 rounded-xl">Belum ada data</div>
                        )}
                    </div>
                </div>

                {/* 2. Savings Trend Line */}
                <div className="rounded-2xl border border-primary/10 bg-white p-5">
                    <div className="flex items-center justify-between mb-4">
                        <div>
                            <h3 className="text-sm font-semibold text-foreground">Tren Tabungan</h3>
                            <p className="text-xs text-muted-foreground mt-0.5">Jumlah & rasio tabungan</p>
                        </div>
                        <span className="text-sm">≡ƒôê</span>
                    </div>
                    <div className="h-[250px]">
                        {savingsLineData.length > 0 ? (
                            <ResponsiveContainer width="100%" height="100%">
                                <LineChart data={savingsLineData} margin={{ top: 5, right: 5, left: -15, bottom: -10 }}>
                                    <CartesianGrid strokeDasharray="3 3" stroke="#f3e8ff" vertical={false} />
                                    <XAxis dataKey="name" tick={{ fontSize: 11, fill: "#9ca3af" }} axisLine={{ stroke: "#f3e8ff" }} tickLine={false} />
                                    <YAxis yAxisId="left" tick={{ fontSize: 10, fill: "#9ca3af" }} axisLine={false} tickLine={false} tickFormatter={(v: number) => v >= 1_000_000 ? `${(v / 1_000_000).toFixed(1)}jt` : `${v / 1000}k`} />
                                    <YAxis yAxisId="right" orientation="right" tick={{ fontSize: 10, fill: "#9ca3af" }} axisLine={false} tickLine={false} tickFormatter={(v: number) => `${v}%`} />
                                    <Tooltip content={<ChartTooltip />} />
                                    <Legend iconType="circle" iconSize={8} wrapperStyle={{ fontSize: "11px", paddingTop: "8px" }} />
                                    <Line yAxisId="left" type="monotone" dataKey="Tabungan" stroke="#3b82f6" strokeWidth={2.5} dot={{ r: 4, fill: "#3b82f6", strokeWidth: 2, stroke: "#fff" }} />
                                    <Line yAxisId="right" type="monotone" dataKey="% Rasio" stroke="#f59e0b" strokeWidth={2} strokeDasharray="5 5" dot={{ r: 3, fill: "#f59e0b", strokeWidth: 2, stroke: "#fff" }} />
                                </LineChart>
                            </ResponsiveContainer>
                        ) : (
                            <div className="h-full flex items-center justify-center text-xs text-muted-foreground border border-dashed border-primary/10 rounded-xl">Belum ada data</div>
                        )}
                    </div>
                </div>

                {/* 3. Spending Distribution Pie */}
                <div className="rounded-2xl border border-primary/10 bg-white p-5">
                    <div className="flex items-center justify-between mb-4">
                        <div>
                            <h3 className="text-sm font-semibold text-foreground">Distribusi Pengeluaran</h3>
                            <p className="text-xs text-muted-foreground mt-0.5">Needs vs Wants vs Savings</p>
                        </div>
                        <span className="text-sm">≡ƒì⌐</span>
                    </div>
                    <div className="h-[250px] flex items-center justify-center">
                        {pieData.length > 0 ? (
                            <ResponsiveContainer width="100%" height="100%">
                                <PieChart>
                                    <Pie
                                        data={pieData}
                                        cx="50%"
                                        cy="50%"
                                        innerRadius={60}
                                        outerRadius={90}
                                        paddingAngle={4}
                                        dataKey="value"
                                        strokeWidth={0}
                                    >
                                        {pieData.map((entry, index) => (
                                            <Cell key={entry.name} fill={entry.fill} />
                                        ))}
                                    </Pie>
                                    {/* eslint-disable-next-line @typescript-eslint/no-explicit-any */}
                                    <Tooltip formatter={(value: any) => formatCurrency(Number(value))} />
                                    <Legend
                                        iconType="circle"
                                        iconSize={8}
                                        wrapperStyle={{ fontSize: "11px" }}
                                        /* eslint-disable-next-line @typescript-eslint/no-explicit-any */
                                        formatter={(value: any) => {
                                            const item = pieData.find((p) => p.name === value);
                                            return `${value} ΓÇö ${item ? formatCurrency(item.value) : ""}`;
                                        }}
                                    />
                                </PieChart>
                            </ResponsiveContainer>
                        ) : (
                            <div className="h-full w-full flex items-center justify-center text-xs text-muted-foreground border border-dashed border-primary/10 rounded-xl">Belum ada data pengeluaran</div>
                        )}
                    </div>
                </div>

                {/* 4. Top Categories Horizontal Bar */}
                <div className="rounded-2xl border border-primary/10 bg-white p-5">
                    <div className="flex items-center justify-between mb-4">
                        <div>
                            <h3 className="text-sm font-semibold text-foreground">Pengeluaran per Kategori</h3>
                            <p className="text-xs text-muted-foreground mt-0.5">Bulan ini</p>
                        </div>
                        <span className="text-sm">≡ƒÅ╖∩╕Å</span>
                    </div>
                    <div className="h-[250px]">
                        {categorySpending.length > 0 ? (
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart data={categorySpending} layout="vertical" margin={{ top: 5, right: 5, left: 10, bottom: 5 }}>
                                    <CartesianGrid strokeDasharray="3 3" stroke="#f3e8ff" horizontal={false} />
                                    <XAxis type="number" tick={{ fontSize: 10, fill: "#9ca3af" }} axisLine={false} tickLine={false} tickFormatter={(v: number) => v >= 1000000 ? `${(v / 1_000_000).toFixed(1)}jt` : `${(v / 1_000).toFixed(0)}rb`} />
                                    <YAxis type="category" dataKey="name" tick={{ fontSize: 10, fill: "#6b7280" }} axisLine={false} tickLine={false} width={100} />
                                    <Tooltip content={<ChartTooltip />} />
                                    <Bar dataKey="Pengeluaran" fill="#a855f7" radius={[0, 6, 6, 0]} barSize={14} />
                                </BarChart>
                            </ResponsiveContainer>
                        ) : (
                            <div className="h-full flex items-center justify-center text-xs text-muted-foreground border border-dashed border-primary/10 rounded-xl">Belum ada data pengeluaran</div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import { Plus, Target, Trophy, Calendar, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { cn, formatCurrency } from "@/lib/utils";
import { useCategories, useSavingGoals } from "@/hooks/use-queries";

function getGoalIcon(icon?: string): string {
    switch (icon) {
        case "ShieldCheck": return "≡ƒ¢í∩╕Å";
        case "Plane": return "Γ£ê∩╕Å";
        case "Laptop": return "≡ƒÆ╗";
        case "GraduationCap": return "≡ƒÄô";
        default: return "≡ƒÄ»";
    }
}

export default function SavingsPage() {
    const { data: categories = [], isLoading: loadingCats } = useCategories();
    const { data: savingGoals = [], isLoading: loadingGoals } = useSavingGoals();

    // Filter only Savings categories
    const savingsCats = categories.filter(c => c.mainCategory === 'Savings');
    const totalSavings = savingsCats.reduce((sum, c) => sum + ((c as any).budget_allocation || 0), 0);

    const activeGoals = savingGoals.filter((g) => !g.isAchieved);
    const achievedGoals = savingGoals.filter((g) => g.isAchieved);

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            {/* Header */}
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
                <div>
                    <h2 className="text-xl font-bold text-foreground">
                        Tabungan & Target ≡ƒÉ╖
                    </h2>
                    <p className="text-sm text-muted-foreground mt-1">
                        Total alokasi tabungan bulan ini{" "}
                        {loadingCats ? (
                            <span className="inline-block translate-y-1"><Loader2 className="h-4 w-4 animate-spin text-blue-600 ml-1" /></span>
                        ) : (
                            <span className="font-currency font-semibold text-blue-600">
                                {formatCurrency(totalSavings)}
                            </span>
                        )}
                    </p>
                </div>
                <Button className="rounded-xl bg-primary hover:bg-primary/90 shadow-lg shadow-primary/25 disabled:opacity-50">
                    <Plus className="h-4 w-4 mr-1.5" />
                    Target Baru
                </Button>
            </div>

            {/* Monthly Savings */}
            <div className="rounded-2xl border border-primary/10 bg-white p-5">
                <div className="flex items-center gap-2 mb-4">
                    <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-blue-50">
                        <span className="text-sm">≡ƒÆ░</span>
                    </div>
                    <div>
                        <h3 className="text-sm font-semibold text-foreground">Tabungan Bulan Ini</h3>
                        <p className="text-xs text-muted-foreground">Sesuai Alokasi Anggaran</p>
                    </div>
                </div>

                <div className="space-y-2">
                    {loadingCats ? (
                        <div className="py-8 flex justify-center"><Loader2 className="h-6 w-6 animate-spin text-primary" /></div>
                    ) : savingsCats.length === 0 ? (
                        <div className="py-4 text-center text-sm text-muted-foreground">Belum ada alokasi tabungan di bulan ini.</div>
                    ) : savingsCats.map((saving) => (
                        <div
                            key={saving.id}
                            className="flex items-center justify-between rounded-xl bg-blue-50/50 px-4 py-3"
                        >
                            <div className="flex items-center gap-3">
                                <span className="text-lg">{saving.icon || '≡ƒÉ╖'}</span>
                                <div>
                                    <p className="text-sm font-medium text-foreground">{saving.name}</p>
                                </div>
                            </div>
                            <span className="text-sm font-currency font-semibold text-blue-600">
                                {formatCurrency((saving as any).budget_allocation || 0)}
                            </span>
                        </div>
                    ))}
                </div>
            </div>

            {/* Active Goals */}
            <div>
                <div className="flex items-center gap-2 mb-3">
                    <Target className="h-4 w-4 text-primary" />
                    <h3 className="text-sm font-semibold text-foreground">Target Aktif</h3>
                    <Badge variant="outline" className="rounded-full text-[10px] border-primary/20 text-primary">
                        {activeGoals.length} target
                    </Badge>
                </div>

                {loadingGoals ? (
                    <div className="py-8 flex justify-center"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>
                ) : activeGoals.length === 0 ? (
                    <div className="py-8 text-center text-sm text-muted-foreground rounded-2xl border border-dashed border-primary/20">
                        Belum ada target tabungan yang aktif.
                    </div>
                ) : (
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                        {activeGoals.map((goal) => {
                            const pct = Math.round((goal.currentAmount / goal.targetAmount) * 100);
                            const remaining = goal.targetAmount - goal.currentAmount;
                            const deadline = new Date(goal.deadline);
                            const monthsLeft = Math.max(
                                0,
                                (deadline.getFullYear() - new Date().getFullYear()) * 12 + (deadline.getMonth() - new Date().getMonth())
                            );

                            return (
                                <div
                                    key={goal.id}
                                    className="group rounded-2xl border border-primary/10 bg-white p-5 transition-all duration-300 hover:shadow-lg hover:shadow-primary/5 hover:border-primary/20"
                                >
                                    {/* Icon & Title */}
                                    <div className="flex items-start justify-between mb-3">
                                        <div className="flex items-center gap-2">
                                            <span className="text-2xl">{getGoalIcon(goal.icon)}</span>
                                            <div>
                                                <p className="text-sm font-semibold text-foreground">{goal.name}</p>
                                                <div className="flex items-center gap-1 mt-0.5">
                                                    <Calendar className="h-3 w-3 text-muted-foreground" />
                                                    <span className="text-[11px] text-muted-foreground">
                                                        {monthsLeft > 0 ? `${monthsLeft} bulan lagi` : 'Bulan ini'}
                                                    </span>
