    const totalIncome = categories.filter(c => c.mainCategory === 'Income').reduce((sum, c) => sum + (c as any).budget_allocation, 0);
    const totalSavings = categories.filter(c => c.mainCategory === 'Savings').reduce((sum, c) => sum + (c as any).budget_allocation, 0);
    const totalAllocated = categories.filter(c => c.mainCategory === 'Needs' || c.mainCategory === 'Wants').reduce((sum, c) => sum + (c as any).budget_allocation, 0);
    const remaining = totalIncome - totalAllocated - totalSavings;

    const cards = [
        {
            label: "Total Pemasukan",
            amount: totalIncome,
            color: "text-emerald-600",
            bg: "bg-emerald-50",
            emoji: "≡ƒÆ░",
        },
        {
            label: "Teralokasi",
            amount: totalAllocated,
            color: "text-primary",
            bg: "bg-primary/10",
            emoji: "≡ƒôï",
        },
        {
            label: "Sisa",
            amount: remaining,
            color: remaining >= 0 ? "text-emerald-600" : "text-destructive",
            bg: remaining >= 0 ? "bg-emerald-50" : "bg-red-50",
            emoji: remaining >= 0 ? "Γ£à" : "ΓÜá∩╕Å",
        },
    ];

    return (
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
            {isLoading ? (
                <div className="col-span-3 text-center py-4 text-sm text-muted-foreground">Memuat data ringkasan...</div>
