                                        <span className="text-[10px] text-muted-foreground">/</span>
                                        <span className="text-xs font-currency text-foreground font-medium">
                                            {formatCurrency(status.allocated)}
                                        </span>
                                    </div>
                                </div>

                                <div className="relative">
                                    <div className="h-2.5 w-full rounded-full bg-primary/10 overflow-hidden">
                                        <div
                                            className={cn(
                                                "h-full rounded-full transition-all duration-700 ease-out",
                                                progressColor
                                            )}
                                            style={{ width: `${Math.min(status.percentage, 100)}%` }}
                                        />
                                    </div>
                                </div>

                                <div className="flex items-center justify-between">
                                    <span
                                        className={cn(
                                            "text-[10px] font-medium rounded-full px-2 py-0.5",
                                            status.percentage > 100
                                                ? "bg-red-50 text-red-600"
                                                : status.percentage >= 80
                                                    ? "bg-amber-50 text-amber-600"
                                                    : status.mainCategory === "Savings"
                                                        ? "bg-blue-50 text-blue-600"
                                                        : "bg-primary/10 text-primary"
                                        )}
                                    >
                                        {getStatusLabel(status.percentage, status.mainCategory)}
                                    </span>
                                    <span className="text-[10px] text-muted-foreground font-currency">
                                        {status.remaining > 0
                                            ? `Sisa ${formatCurrency(status.remaining)}`
                                            : status.mainCategory === "Savings"
                                                ? "Target tercapai Γ£ô"
                                                : "Habis!"}
                                    </span>
                                </div>
                            </div>
                        );
                    }))}
            </div>
        </div>
    );
}

"use client";

import {
    ResponsiveContainer,
    LineChart,
    Line,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
} from "recharts";
import { formatCurrency } from "@/lib/utils";
import { useMonthlyTrend } from "@/hooks/use-queries";
import { useUIStore } from "@/stores/ui-store";
import { MONTH_NAMES } from "@/lib/constants";



function CustomTooltip({ active, payload, label }: { active?: boolean; payload?: Array<{ value: number; color: string; name: string }>; label?: string }) {
    if (!active || !payload) return null;

    return (
        <div className="rounded-xl border border-primary/15 bg-white/95 backdrop-blur-sm p-3 shadow-xl shadow-primary/5">
            <p className="text-xs font-semibold text-foreground mb-2">{label}</p>
            <div className="space-y-1.5">
                {payload.map((entry) => (
                    <div key={entry.name} className="flex items-center gap-2">
                        <div
                            className="h-2 w-2 rounded-full"
                            style={{ backgroundColor: entry.color }}
                        />
                        <span className="text-[11px] text-muted-foreground">{entry.name}</span>
                        <span className="text-[11px] font-currency font-semibold text-foreground ml-auto">
                            {formatCurrency(entry.value)}
                        </span>
                    </div>
                ))}
            </div>
        </div>
    );
}

export function MonthlyTrendChart() {
    const { currentMonth, currentYear } = useUIStore();
    const { data: trendData, isLoading } = useMonthlyTrend(currentMonth, currentYear);

    const chartData = trendData?.map((d) => ({
        name: MONTH_NAMES[d.month - 1]?.substring(0, 3) ?? `${d.month}`,
        Pemasukan: d.income,
        Pengeluaran: d.expenses,
        Tabungan: d.savings,
    })) || [];

    return (
        <div className="rounded-2xl border border-primary/10 bg-white p-5 transition-all duration-300 hover:shadow-lg hover:shadow-primary/5">
            <div className="flex items-center justify-between mb-5">
                <div>
                    <h3 className="text-sm font-semibold text-foreground">Tren Bulanan</h3>
                    <p className="text-xs text-muted-foreground mt-0.5">6 bulan terakhir</p>
                </div>
                <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-primary/10 text-sm">
                    ≡ƒôê
                </div>
            </div>

            <div className="h-[260px] w-full">
                {isLoading ? (
                    <div className="w-full h-full flex items-end gap-2 pb-5 pt-8 px-2 animate-pulse">
                        {[1, 2, 3, 4, 5, 6].map((i) => (
                            <div key={i} className="flex-1 bg-primary/10 rounded-t-sm" style={{ height: `${Math.max(20, Math.random() * 100)}%` }} />
                        ))}
                    </div>
                ) : (
                    <ResponsiveContainer width="100%" height="100%">
                        <LineChart data={chartData} margin={{ top: 5, right: 5, left: -15, bottom: 5 }}>
                            <CartesianGrid strokeDasharray="3 3" stroke="#f3e8ff" vertical={false} />
                            <XAxis
                                dataKey="name"
                                tick={{ fontSize: 11, fill: "#9ca3af" }}
                                axisLine={{ stroke: "#f3e8ff" }}
                                tickLine={false}
                            />
                            <YAxis
                                tick={{ fontSize: 10, fill: "#9ca3af" }}
                                axisLine={false}
                                tickLine={false}
                                tickFormatter={(v: number) => `${(v / 1_000_000).toFixed(0)}jt`}
                            />
                            <Tooltip content={<CustomTooltip />} />
                            <Legend
                                iconType="circle"
                                iconSize={8}
                                wrapperStyle={{ fontSize: "11px", paddingTop: "8px" }}
                            />
                            <Line
                                type="monotone"
                                dataKey="Pemasukan"
                                stroke="#22c55e"
                                strokeWidth={2.5}
                                dot={{ r: 4, fill: "#22c55e", strokeWidth: 2, stroke: "#fff" }}
                                activeDot={{ r: 6, fill: "#22c55e", stroke: "#fff", strokeWidth: 3 }}
                            />
                            <Line
                                type="monotone"
                                dataKey="Pengeluaran"
                                stroke="#a855f7"
                                strokeWidth={2.5}
                                dot={{ r: 4, fill: "#a855f7", strokeWidth: 2, stroke: "#fff" }}
                                activeDot={{ r: 6, fill: "#a855f7", stroke: "#fff", strokeWidth: 3 }}
                            />
                            <Line
                                type="monotone"
                                dataKey="Tabungan"
                                stroke="#3b82f6"
                                strokeWidth={2}
                                strokeDasharray="5 5"
                                dot={{ r: 3, fill: "#3b82f6", strokeWidth: 2, stroke: "#fff" }}
                                activeDot={{ r: 5, fill: "#3b82f6", stroke: "#fff", strokeWidth: 3 }}
                            />
                        </LineChart>
                    </ResponsiveContainer>
                )}
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { Plus, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { useCategories, useCreateTransaction } from "@/hooks/use-queries";
import { toast } from "sonner";

const accountNames = ["Cash", "Bank Mandiri", "BCA", "GoPay", "Credit Card"];

export function AddTransactionDialog() {
    const [open, setOpen] = useState(false);
    const { data: categories = [], isLoading: isLoadingCats } = useCategories();
    const createTx = useCreateTransaction();

    const [form, setForm] = useState({
        description: "",
        amount: "",
        categoryId: "",
        accountName: "",
        date: new Date().toISOString().split("T")[0],
        isRecurring: false,
    });

    const handleSubmit = async () => {
        if (!form.description || !form.amount || !form.categoryId || !form.accountName) return;

        const selectedCat = categories.find(c => c.id === form.categoryId);
        const isIncome = selectedCat?.mainCategory === "Income";
        const finalAmount = isIncome ? Number(form.amount) : -Number(form.amount);

        try {
            await createTx.mutateAsync({
                description: form.description,
                amount: finalAmount,
                categoryId: form.categoryId,
                accountName: form.accountName,
                date: form.date,
                isRecurring: form.isRecurring,
            });
            toast.success("Transaksi berhasil ditambahkan");
            setOpen(false);
            setForm({
                description: "",
                amount: "",
                categoryId: "",
                accountName: "",
                date: new Date().toISOString().split("T")[0],
                isRecurring: false,
            });
        } catch (error) {
            toast.error("Gagal menambahkan transaksi");
        }
    };

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
                <Button className="rounded-xl bg-primary hover:bg-primary/90 shadow-lg shadow-primary/25">
                    <Plus className="h-4 w-4 mr-1.5" />
                    Tambah Transaksi
                </Button>
            </DialogTrigger>
            <DialogContent className="sm:max-w-md rounded-2xl border-primary/15">
                <DialogHeader>
                    <DialogTitle className="text-lg font-semibold">
                        Transaksi Baru Γ£Å∩╕Å
                    </DialogTitle>
                </DialogHeader>

                <div className="space-y-4 mt-2">
                    {/* Description */}
                    <div className="space-y-1.5">
                        <Label className="text-xs font-medium text-foreground">Deskripsi</Label>
                        <Input
                            value={form.description}
                            onChange={(e) => setForm((p) => ({ ...p, description: e.target.value }))}
                            placeholder="Contoh: Belanja mingguan..."
                            className="h-10 rounded-xl border-primary/15 focus-visible:ring-primary/30"
                        />
                    </div>

                    {/* Amount */}
                    <div className="space-y-1.5">
                        <Label className="text-xs font-medium text-foreground">Jumlah (Rp)</Label>
                        <Input
                            type="number"
                            value={form.amount}
                            onChange={(e) => setForm((p) => ({ ...p, amount: e.target.value }))}
                            placeholder="0"
                            className="h-10 font-currency rounded-xl border-primary/15 focus-visible:ring-primary/30"
                        />
                    </div>

                    {/* Category & Account row */}
                    <div className="grid grid-cols-2 gap-3">
                        <div className="space-y-1.5">
                            <Label className="text-xs font-medium text-foreground">Kategori</Label>
                            <Select
                                value={form.categoryId}
                                onValueChange={(v) => setForm((p) => ({ ...p, categoryId: v }))}
                            >
                                <SelectTrigger className="h-10 rounded-xl border-primary/15 focus:ring-primary/30 text-sm">
                                    <SelectValue placeholder="Pilih..." />
                                </SelectTrigger>
                                <SelectContent className="rounded-xl border-primary/15">
                                    {isLoadingCats ? (
                                        <SelectItem value="loading" disabled>Memuat kategori...</SelectItem>
                                    ) : (
                                        categories.map((cat) => (
                                            <SelectItem key={cat.id} value={cat.id} className="text-sm">
                                                {cat.name} ({cat.mainCategory})
                                            </SelectItem>
                                        ))
                                    )}
                                </SelectContent>
                            </Select>
                        </div>

                        <div className="space-y-1.5">
                            <Label className="text-xs font-medium text-foreground">Akun</Label>
                            <Select
                                value={form.accountName}
                                onValueChange={(v) => setForm((p) => ({ ...p, accountName: v }))}
                            >
                                <SelectTrigger className="h-10 rounded-xl border-primary/15 focus:ring-primary/30 text-sm">
                                    <SelectValue placeholder="Pilih..." />
                                </SelectTrigger>
                                <SelectContent className="rounded-xl border-primary/15">
                                    {accountNames.map((acc) => (
                                        <SelectItem key={acc} value={acc} className="text-sm">
                                            {acc}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                    </div>

                    {/* Date */}
                    <div className="space-y-1.5">
                        <Label className="text-xs font-medium text-foreground">Tanggal</Label>
                        <Input
                            type="date"
                            value={form.date}
                            onChange={(e) => setForm((p) => ({ ...p, date: e.target.value }))}
                            className="h-10 rounded-xl border-primary/15 focus-visible:ring-primary/30"
                        />
                    </div>

                    {/* Recurring toggle */}
                    <div className="flex items-center justify-between rounded-xl bg-primary/5 px-3 py-2.5">
                        <div>
                            <p className="text-sm font-medium text-foreground">Transaksi berulang?</p>
                            <p className="text-[11px] text-muted-foreground">Otomatis setiap bulan</p>
                        </div>
                        <Switch
                            checked={form.isRecurring}
                            onCheckedChange={(v) => setForm((p) => ({ ...p, isRecurring: v }))}
                        />
                    </div>

                    {/* Submit */}
                    <Button
                        onClick={handleSubmit}
                        className="w-full h-10 rounded-xl bg-primary hover:bg-primary/90 font-medium"
                        disabled={!form.description || !form.amount || !form.categoryId || !form.accountName || createTx.isPending}
                    >
                        {createTx.isPending ? (
                            <>
                                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                Menyimpan...
                            </>
                        ) : (
                            "Simpan Transaksi"
                        )}
                    </Button>
                </div>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import { Search, Filter, X } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import { mockCategories } from "@/lib/mock-data";
import type { MainCategory } from "@/types";

interface TransactionFiltersProps {
    search: string;
    onSearchChange: (value: string) => void;
    mainCategory: MainCategory | null;
    onMainCategoryChange: (value: MainCategory | null) => void;
    accountName: string | null;
    onAccountNameChange: (value: string | null) => void;
}

const mainCategories: { value: MainCategory; label: string; emoji: string }[] = [
    { value: "Needs", label: "Kebutuhan", emoji: "≡ƒÅá" },
    { value: "Wants", label: "Keinginan", emoji: "Γ£¿" },
    { value: "Savings", label: "Tabungan", emoji: "≡ƒÉ╖" },
];

const accountNames = ["Cash", "Bank Mandiri", "BCA", "GoPay", "Credit Card"];

export function TransactionFilters({
    search,
    onSearchChange,
    mainCategory,
    onMainCategoryChange,
    accountName,
    onAccountNameChange,
}: TransactionFiltersProps) {
    const hasFilters = mainCategory !== null || accountName !== null;

    const clearFilters = () => {
        onMainCategoryChange(null);
        onAccountNameChange(null);
    };

    return (
        <div className="rounded-2xl border border-primary/10 bg-white p-4 space-y-3">
            {/* Search */}
            <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                    value={search}
                    onChange={(e) => onSearchChange(e.target.value)}
                    placeholder="Cari transaksi..."
                    className="pl-9 h-10 rounded-xl border-primary/15 focus-visible:ring-primary/30"
                />
            </div>

            {/* Filter Tags */}
            <div className="flex flex-wrap items-center gap-2">
                <Filter className="h-3.5 w-3.5 text-muted-foreground" />

                {/* Main Category */}
                {mainCategories.map((mc) => (
                    <Badge
                        key={mc.value}
                        variant="outline"
                        className={cn(
                            "cursor-pointer rounded-full px-3 py-1 text-[11px] font-medium transition-all border",
                            mainCategory === mc.value
                                ? "bg-primary text-white border-primary"
                                : "bg-white text-foreground border-primary/15 hover:border-primary/30"
                        )}
                        onClick={() =>
                            onMainCategoryChange(mainCategory === mc.value ? null : mc.value)
                        }
                    >
                        <span className="mr-1">{mc.emoji}</span>
                        {mc.label}
                    </Badge>
                ))}

                <span className="text-[10px] text-muted-foreground">|</span>

                {/* Account */}
                {accountNames.map((acc) => (
                    <Badge
                        key={acc}
                        variant="outline"
                        className={cn(
                            "cursor-pointer rounded-full px-2.5 py-1 text-[11px] font-medium transition-all border",
                            accountName === acc
                                ? "bg-primary text-white border-primary"
                                : "bg-white text-foreground border-primary/15 hover:border-primary/30"
                        )}
                        onClick={() => onAccountNameChange(accountName === acc ? null : acc)}
                    >
                        {acc}
                    </Badge>
                ))}

                {hasFilters && (
                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={clearFilters}
                        className="h-6 px-2 text-[11px] text-muted-foreground hover:text-destructive"
                    >
                        <X className="h-3 w-3 mr-1" />
                        Reset
                    </Button>
                )}
            </div>
        </div>
    );
}

"use client";

import {
    Home, ShoppingCart, Car, Wifi, Shield, Film,
    UtensilsCrossed, ShoppingBag, Heart, CreditCard,
    ShieldCheck, TrendingUp, RotateCcw,
} from "lucide-react";
import { cn, formatCurrency, formatDate } from "@/lib/utils";
import { Badge } from "@/components/ui/badge";
import type { Transaction, Category } from "@/types";

const iconMap: Record<string, React.ElementType> = {
    Home, ShoppingCart, Car, Wifi, Shield, Film,
    UtensilsCrossed, ShoppingBag, Heart, CreditCard,
    ShieldCheck, TrendingUp,
};

function getCategoryBadgeStyle(mainCategory: string) {
    switch (mainCategory) {
        case "Needs": return "bg-purple-50 text-purple-700 border-purple-200";
        case "Wants": return "bg-fuchsia-50 text-fuchsia-700 border-fuchsia-200";
        case "Savings": return "bg-blue-50 text-blue-700 border-blue-200";
        default: return "bg-gray-50 text-gray-700 border-gray-200";
    }
}

function getCategoryLabel(mainCategory: string) {
    switch (mainCategory) {
        case "Needs": return "Kebutuhan";
        case "Wants": return "Keinginan";
        case "Savings": return "Tabungan";
        default: return mainCategory;
    }
}

interface TransactionTableProps {
    transactions: (Transaction & { category: Category })[];
}

export function TransactionTable({ transactions }: TransactionTableProps) {
    if (transactions.length === 0) {
        return (
            <div className="rounded-2xl border border-primary/10 bg-white p-10 text-center">
                <p className="text-3xl mb-2">≡ƒöì</p>
                <p className="text-sm font-medium text-foreground">Tidak ada transaksi</p>
                <p className="text-xs text-muted-foreground mt-1">Ubah filter atau tambah transaksi baru</p>
            </div>
        );
    }

    return (
        <div className="rounded-2xl border border-primary/10 bg-white overflow-hidden">
            {/* Desktop Table Header */}
            <div className="hidden sm:grid sm:grid-cols-[1fr_120px_120px_120px_100px] gap-2 px-4 py-2.5 bg-primary/5 border-b border-primary/10">
                <span className="text-[11px] font-semibold text-muted-foreground uppercase tracking-wider">Transaksi</span>
                <span className="text-[11px] font-semibold text-muted-foreground uppercase tracking-wider">Kategori</span>
                <span className="text-[11px] font-semibold text-muted-foreground uppercase tracking-wider">Akun</span>
                <span className="text-[11px] font-semibold text-muted-foreground uppercase tracking-wider text-right">Jumlah</span>
                <span className="text-[11px] font-semibold text-muted-foreground uppercase tracking-wider text-right">Tanggal</span>
            </div>

            {/* Rows */}
            <div className="divide-y divide-primary/5">
                {transactions.map((txn) => {
                    const Icon = iconMap[txn.category.icon ?? ""] ?? CreditCard;
                    const isExpense = txn.amount < 0;

                    return (
                        <div
                            key={txn.id}
                            className="group flex flex-col sm:grid sm:grid-cols-[1fr_120px_120px_120px_100px] gap-1 sm:gap-2 sm:items-center px-4 py-3 hover:bg-primary/3 transition-colors cursor-pointer"
                        >
                            {/* Transaction info */}
                            <div className="flex items-center gap-3">
                                <div className={cn(
                                    "flex h-8 w-8 shrink-0 items-center justify-center rounded-lg",
                                    isExpense ? "bg-rose-50" : "bg-emerald-50"
                                )}>
                                    <Icon className={cn("h-3.5 w-3.5", isExpense ? "text-rose-500" : "text-emerald-500")} />
                                </div>
                                <div className="min-w-0">
                                    <p className="text-sm font-medium text-foreground truncate">
                                        {txn.description}
                                    </p>
                                    {txn.isRecurring && (
                                        <span className="inline-flex items-center gap-1 text-[10px] text-muted-foreground">
                                            <RotateCcw className="h-2.5 w-2.5" /> Berulang
                                        </span>
                                    )}
                                </div>
                            </div>

                            {/* Category */}
                            <div>
                                <Badge
                                    variant="outline"
                                    className={cn(
                                        "text-[10px] px-2 py-0.5 rounded-full font-medium border",
                                        getCategoryBadgeStyle(txn.category.mainCategory)
                                    )}
                                >
                                    {txn.category.name}
                                </Badge>
                            </div>

                            {/* Account */}
                            <span className="text-xs text-muted-foreground">{txn.accountName}</span>

                            {/* Amount */}
                            <span className={cn(
                                "text-sm font-semibold font-currency whitespace-nowrap sm:text-right",
                                isExpense ? "text-rose-500" : "text-emerald-600"
                            )}>
                                {isExpense ? "-" : "+"}{formatCurrency(Math.abs(txn.amount))}
                            </span>

                            {/* Date */}
                            <span className="text-xs text-muted-foreground sm:text-right">
                                {formatDate(txn.date)}
                            </span>
                        </div>
                    );
                })}
            </div>
        </div>
    );
}

messages.message:
Error: Calling setState synchronously within an effect can trigger cascading renders

Effects are intended to synchronize state between React and external systems such as manually updating the DOM, state management libraries, or other platform APIs. In general, the body of an effect should do one or both of the following:
* Update external systems with the latest state from React.
